'use client';
import { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Plus } from 'lucide-react';
import { useDebounce } from 'use-debounce';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import EditHallDialog from '@/components/dialog/EditHallDialog';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/context/AuthContext';
import { HallType } from '@/types';
import SearchInput from '@/components/ui/SearchInput';
import Pagination from '@/components/ui/Pagination';
import { Loading } from '@/components/ui/Loading';
import NotFound from '@/components/ui/NotFound';
import HallCard from '@/components/ui/HallCard';
import { AddHallDialog } from '@/components/dialog/AddHallDialog';
import { fetchHalls } from '@/api/halls';

const AdminHallsPage = () => {
  const { toast } = useToast();
  const { token } = useAuth();

  const [halls, setHalls] = useState<HallType[]>([]);
  const [selectedHall, setSelectedHall] = useState<HallType | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);

  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  
  const [loading, setLoading] = useState(false);

  // pagination محلي
  const [currentPage, setCurrentPage] = useState(1);
  const [hallsPerPage] = useState(6);

  // 🟣 جلب القاعات مرة واحدة فقط عند تحميل الصفحة
  useEffect(() => {
    if(token){
      fetchHalls(setLoading, currentPage, hallsPerPage, true, toast).then(
        (data) => {
          if (data) setHalls(data);
        }
      );
    }
  }, [currentPage,token]);
  // 🟢 Delete Hall
  const handleDelete = async () => {
    if (!selectedHall) return;
    try {
      const res = await fetch(
        `http://localhost:8080/halls/${selectedHall._id}`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );

      const data = await res.json();

      if (res.ok) {
        setHalls((prev) => prev.filter((h) => h._id !== selectedHall._id));
        toast({
          title: 'Deleted Successfully',
          description: `${selectedHall.name} has been deleted.`,
          className: 'bg-green-500 text-white',
        });
      } else {
        throw new Error(data.message || 'Failed to delete hall');
      }
    } catch (err: any) {
      toast({
        title: 'Error',
        description: err.message,
        variant: 'destructive',
      });
    } finally {
      setIsDeleteDialogOpen(false);
      setSelectedHall(null);
    }
  };
  //  Create New Hall
  const handleCreate = async (newHall: HallType) => {
    try {
      const response = await fetch(`http://localhost:8080/halls`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newHall),
      });

      const data = await response.json();

      toast({
        title: 'successfully!',
        description: data.message || 'Category added successfully!',
        className: 'bg-green-600 text-white border-0',
      });

      setHalls((prev) => [...prev, data.categories]);
      // Optionally re-fetch categories or just append:
      setIsAddDialogOpen(false);

      fetchHalls(setLoading, currentPage, hallsPerPage, true, toast).then(
        (data) => setHalls(data)
      );
    } catch (error: any) {
      toast({
        title: 'error',
        description: error.message || 'Something went wrong.',
        variant: 'destructive',
      });
    }
  };

  // 🔍 local search
  const filteredHalls = (halls || [])?.filter(
    (hall) =>
      hall?.name.toLowerCase().includes(debouncedQuery.toLowerCase()) ||
      hall?.location.toLowerCase().includes(debouncedQuery.toLowerCase())
  );

  // 📄 Pagination محلي
  const indexOfLast = currentPage * hallsPerPage;
  const indexOfFirst = indexOfLast - hallsPerPage;
  const currentHalls = filteredHalls.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredHalls.length / hallsPerPage);

  // عند تغيير البحث رجع للصفحة الأولى
  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedQuery]);

  if (loading) return <Loading />;
  return (
    <div className='p-6 space-y-6'>
      {/* 🔍 شريط البحث + زر الإضافة */}
      <div className='flex justify-between items-center gap-4 flex-wrap'>
        <SearchInput
          name='Hall'
          searchQuery={searchQuery}
          setSearchQuery={setSearchQuery}
          setCurrentPage={() => setCurrentPage(1)}
        />
        <Button
          onClick={() => setIsAddDialogOpen(true)}
          className='gap-2 bg-purple-700 hover:bg-purple-800 text-white'
        >
          <Plus className='h-4 w-4' /> Add Hall
        </Button>
      </div>

      {/* 🏛️ عرض القاعات */}
      {currentHalls.length > 0 ? (
        <div className='grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6'>
          {currentHalls.map((hall, index) => (
            <HallCard
              key={index}
              hall={hall}
              isAdmin
              onEdit={() => {
                setSelectedHall(hall);
                setIsEditDialogOpen(true);
              }}
              onDelete={() => {
                setSelectedHall(hall);
                setIsDeleteDialogOpen(true);
              }}
            />
          ))}
        </div>
      ) : (
        <NotFound message='No halls found' />
      )}

      {/* 📄 Pagination */}
      {filteredHalls.length > 0 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          paginate={setCurrentPage}
        />
      )}

      {/* (Dialogs) */}
      <EditHallDialog
        open={isEditDialogOpen}
        onClose={() => setIsEditDialogOpen(false)}
        hall={selectedHall}
        token={token}
        onSuccess={(updatedHall) => {
          setHalls((prev) =>
            prev.map((h) => (h?._id === updatedHall?._id ? updatedHall : h))
          );
          setIsEditDialogOpen(false);
        }}
        toast={toast}
      />

      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onClose={() => setIsDeleteDialogOpen(false)}
        title='Delete Hall'
        description={`Are you sure you want to delete ${selectedHall?.name}?`}
        onConfirm={handleDelete}
      />

      <AddHallDialog
        open={isAddDialogOpen}
        onClose={() => setIsAddDialogOpen(false)}
        onSubmit={handleCreate}
      />
    </div>
  );
};

export default AdminHallsPage;
